use std::convert::AsRef;

struct TextWrapper(String);

impl AsRef<str> for TextWrapper {
    fn as_ref(&self) -> &str {
        &self.0
    }
}

fn process_text<T: AsRef<str>>(input: T) {
    let text = input.as_ref();
    println!("Successfully processed text: {}", text);
}

fn process_mutable_text<T>(mut input: T) -> Result<String, &'static str>
where
    T: AsRef<str> + std::fmt::Debug
{
    let initial_text = input.as_ref();
    println!("Initial state debugged: {:?}", initial_text);

    // Simulate modification using AsMut pattern conceptually, though direct mutability on generic T is tricky.
    // We will stick to consuming the AsRef result for simplicity here.
    let new_string = format!("Modified version of {}", initial_text);
    Ok(new_string)
}

fn main() {
    // Test with &str (slice)
    process_text("Hello world slice".to_string());

    // Test with String
    let s = String::from("Another string test");
    process_text(s);

    // Test with custom wrapper
    let w = TextWrapper(String::from("Custom wrapper test"));
    process_text(w);

    // Test mutable pattern concept (passing a String that we can conceptually treat as mutable input)
    let mut s_mut = String::from("Original data for mutation");
    match process_mutable_text(s_mut) {
        Ok(result) => println!("Mutation successful: {}", result),
        Err(e) => println!("Mutation failed: {}", e),
    }
}

